var e=[{id:`L4_1`,type:`dialog`,speaker:`AGENT_GRONIA_NULL_NULL`,text:{KOREA:`허억……!`,JPN:`はあっ……！`,ENG:`*Gasp...!*`,TWN:`呃呃……！`},stage:{bg:`GRONIA_STREET`,slots:{L:null,C:{char_id:`AGENT_GRONIA_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L7_1`,type:`dialog`,speaker:`AGENT_GRONIA_NULL_NULL`,text:{KOREA:`헉……!`,JPN:`はっ……！`,ENG:`*Gasp...!*`,TWN:`呃……！`},stage:{bg:`GRONIA_STREET`,slots:{L:null,C:{char_id:`AGENT_GRONIA_NULL_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L13_1`,type:`dialog`,speaker:`AGENT_GRONIA_NULL_NULL`,text:{KOREA:`허억……! 헉……!`,JPN:`はぁ……！　はぁ……！`,ENG:`*Huff…!* *Huff…!* *Huff…!*`,TWN:`呃呃……！呃……！`},stage:{bg:`GRONIA_STREET`,slots:{L:null,C:null,R:null}}},{id:`L14_1`,type:`dialog`,speaker:`OLD_GRONIA_NULL_NULL`,text:{KOREA:`레아……? 레아야, 괜찮니……?`,JPN:`レア……？　レア、大丈夫……？`,ENG:`Leah...? Leah, are you alright...?`,TWN:`蕾亞……？蕾亞？你沒事吧……？`},stage:{bg:`GRONIA_STREET`,slots:{L:null,C:null,R:{char_id:`OLD_GRONIA_NULL_NULL`,face:`UNIT_SURPRISE`}}}},{id:`L17_1`,type:`dialog`,speaker:`ROOKIE_GRONIA_NULL_NULL`,text:{KOREA:`레버넌트 씨! 정신 차리고 어서 일어나요!`,JPN:`レヴナントさん！　しっかりして、早く起きてください！`,ENG:`Revenant! Pull yourself together! Stand up!`,TWN:`亡靈小姐！你振作一點，快醒醒！`},stage:{bg:`GRONIA_STREET`,slots:{L:null,C:{char_id:`ROOKIE_GRONIA_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L18_1`,type:`dialog`,speaker:`ROOKIE_GRONIA_NULL_NULL`,text:{KOREA:`사방에 침식체들이라고요! 멍하니 있다간 죽어요!`,JPN:`周りが侵食体でいっぱいですよ！　ぼっとしていると死にます！`,ENG:`There are Corrupted Objects everywhere! If you keep spacing out like that, you’ll die!`,TWN:`現在周圍都是侵蝕體！昏倒的話會死掉的！`},stage:{bg:`GRONIA_STREET`,slots:{L:null,C:{char_id:`ROOKIE_GRONIA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L19_1`,type:`dialog`,speaker:`AGENT_GRONIA_NULL_NULL`,text:{KOREA:`엄마…….`,JPN:`お母さん……`,ENG:`Mom...`,TWN:`媽……`},stage:{bg:`GRONIA_STREET`,slots:{L:null,C:{char_id:`AGENT_GRONIA_NULL_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L20_1`,type:`dialog`,speaker:`AGENT_GRONIA_NULL_NULL`,text:{KOREA:`우리 엄마…… 만……. 데리고…….`,JPN:`お母さん……だけ……連れて……`,ENG:`Take... Mom... And...`,TWN:`帶……帶我……媽……`},stage:{bg:`GRONIA_STREET`,slots:{L:null,C:{char_id:`AGENT_GRONIA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L21_1`,type:`dialog`,speaker:`ROOKIE_GRONIA_NULL_NULL`,text:{KOREA:`수훈자는 손이 네 개인 줄 알아요?! 제가 휠체어 밀 동안 지켜 줄 사람은 있어야죠!`,JPN:`受勲者は手が四つあるとでも思ってるんですか！？　車椅子を押す間に援護する人が必要でしょ！`,ENG:`You think a war hero has four hands or what?! I need someone to cover me while I push this wheelchair!`,TWN:`你以為授勳者有四隻手嗎？在我推輪椅的時候，總得有人掩護我吧！`},stage:{bg:`GRONIA_STREET`,slots:{L:null,C:{char_id:`ROOKIE_GRONIA_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L25_1`,type:`dialog`,speaker:`CONDUCT_HARMONY_NULL_NULL`,text:{KOREA:`그렇다고 하는군요. 제법 귀여운 아이인데 앙칼진 구석이 있네요.`,JPN:`だそうです。結構かわいいのにツンツンしたところがありますね。`,ENG:`Ah, so that’s what you meant. She’s quite a cute child, but has a bit of an edge.`,TWN:`原來是這樣，長得可愛可愛的，也是有脾氣的呢。`},stage:{bg:`LABORATORY_02`,slots:{L:null,C:{char_id:`CONDUCT_HARMONY_NULL_NULL`,face:`UNIT_PRIDE`},R:null}}},{id:`L26_1`,type:`dialog`,speaker:`AGENT_GRONIA_NULL_NULL`,text:{KOREA:`……가 줘.`,JPN:`……行って。`,ENG:`...Go.`,TWN:`……走。`},stage:{bg:`LABORATORY_02`,slots:{L:null,C:{char_id:`AGENT_GRONIA_NULL_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L29_1`,type:`dialog`,speaker:`AGENT_GRONIA_NULL_NULL`,text:{KOREA:`넌…… 마에스트로? 여긴 어디지?`,JPN:`君は……マエストロ？　ここはどこ？`,ENG:`Are you... Maestra? Where am I?`,TWN:`你是……指揮家？這裡是哪裡？`},stage:{bg:`FALL_PARK`,slots:{L:null,C:{char_id:`AGENT_GRONIA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L30_1`,type:`dialog`,speaker:`CONDUCT_HARMONY_NULL_NULL`,text:{KOREA:`어디도 아닙니다. 눈을 감고 상상하면 떠오르는 무질서한 형태에 색을 입힌 정도죠.`,JPN:`どこでもありません。目を閉じて想像すれば浮かび上がる、無秩序な形に色をつけただけです。`,ENG:`Nowhere. It is nothing more than the chaotic void you see when you close your eyes, only with a few more colors.`,TWN:`哪裡也不是，你閉上眼睛試著想像一下，就像是替浮現的失序狀態上色的感覺。`},stage:{bg:`COUNTERSIDE_FOREST`,slots:{L:null,C:{char_id:`CONDUCT_HARMONY_NULL_NULL`,face:`UNIT_LAUGH`},R:null}}},{id:`L31_1`,type:`dialog`,speaker:`AGENT_GRONIA_NULL_NULL`,text:{KOREA:`…….`,JPN:`……`,ENG:`…`,TWN:`……`},stage:{bg:`VILLAGE2`,slots:{L:null,C:{char_id:`AGENT_GRONIA_NULL_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L33_1`,type:`dialog`,speaker:`CONDUCT_HARMONY_NULL_NULL`,text:{KOREA:`<color=#ffd34c>저</color>는 지금 갑작스럽게 나타난 짙은 역병의 기운에 몸을 가누지 못하는 상태입니다.`,JPN:`<color=#ffd34c>私</color>は今、突然現れた深い疫病の気配で体を動かせない状態です。`,ENG:`<color=#ffd34c>I</color> cannot handle the plague that has suddenly appeared in my present form.`,TWN:`<color=#ffd34c>我</color>現在因為突然出現的瘟疫，導致身體不受控。`},stage:{bg:`COUNTERSIDE_NORMAL`,slots:{L:null,C:{char_id:`CONDUCT_HARMONY_NULL_NULL`,face:`UNIT_IDLE`},R:null}}}];export{e as default};